module arq_protocol(  
    input clk,  
    input reset,  
    input ack,  
    input [4:0] data_in,  
    output reg [4:0] data_out,  
    output reg resend  
);  
    reg [1:0] arq_state;  
    parameter IDLE = 2'b00, SEND = 2'b01, WAIT_ACK = 2'b10;  

    always @(posedge clk or posedge reset) begin  
        if (reset) begin  
            arq_state <= IDLE;  
            resend <= 0;  
        end else begin  
            case (arq_state)  
                IDLE: begin  
                    data_out <= data_in;  
                    resend <= 0;  
                    arq_state <= SEND;  
                end  
                SEND: begin  
                    if (ack) begin  
                        arq_state <= IDLE;  
                    end else begin  
                        resend <= 1;  
                        arq_state <= WAIT_ACK;  
                    end  
                end  
                WAIT_ACK: begin  
                    if (ack) begin  
                        resend <= 0;  
                        arq_state <= IDLE;  
                    end else begin  
                        resend <= 1;  
                    end  
                end  
            endcase  
        end  
    end  
endmodule
